  boolean conversionTrigger = false;
  boolean rehireTrigger = false;
  String newRehireType=null;
  String previousAction=null;
  String newAction=null;

  
 // Logger logger = Logger.getLogger("com.CustomLogs");

  String newType = null;    
  String previousType= null;
 

   try{
    if(previousIdentity != null && newIdentity!= null){
       newType = newIdentity.getType();    
       previousType= previousIdentity.getType(); 
      log.trace("Ascension-Rule-Trigger-TypeChange::identityName= "+newIdentity.getName());

     // boolean isInactiveUser=newIdentity.isInactive();
      if(previousIdentity.isInactive() && !newIdentity.isInactive()){
         return false;
      }


            log.trace("Ascension-Rule-Trigger-TypeChange:: -- previousType:::"+previousType+" newType:::"+newType); 

      if(previousType!=null &&  newType!=null && !(previousType.equalsIgnoreCase(newType)) && (newType.equalsIgnoreCase("employee") && (previousType.equalsIgnoreCase("contractor") )) ){
        log.trace("Ascension-Rule-Trigger-TypeChange:: -- event triggered:::"); 
          return true;

        }

    }
    return false;

  }catch(Exception e){
    logger.debug("Exception= ");
    e.printStackTrace();
    throw e;
  }
